// export default MobileRecharge;
import React, { useState, useEffect, useCallback } from 'react';
import {
  Typography,
  TextField,
  Button,
  Container,
  Paper,
  Tabs,
  Tab,
  Box,
  Grid,
  Autocomplete,
  CircularProgress,
  Chip,
  Link
} from '@mui/material';
import { styled } from '@mui/system';
import { PhoneAndroid, SimCard, Payment, CheckCircle, Edit } from '@mui/icons-material';
import { toast } from 'react-toastify';
import MobilePlan from "./mobilePalan/MobilePlan";
import { billPayRecharge, getRechargeCircle, mobilePlanDetails, rechargeOperators } from "../../../../../api/login/Login";
import 'react-toastify/dist/ReactToastify.css';

import MobileRechargeList from "./mobileRechargeList/MobileRechargeList";
import Loader from "../../../../../common/loader/Loader";
import TipinModal from "../../../../../common/tipinModal/TipinModal";
import InsufficientBalanceModal from "../../../../../common/tipinModal/InsufficientBalanceModal";
import { motion } from 'framer-motion';
import { getLocation } from '../../../../../utils/getLocation';

const StyledPaper = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(4),
  marginTop: theme.spacing(4),
  borderRadius: '20px',
  boxShadow: '0 8px 32px rgba(0,0,0,0.1)',
  background: 'linear-gradient(145deg, #f3f4f6 0%, #fff 100%)',
}));

const AnimatedButton = styled(motion.div)({
  display: 'inline-block',
  width: '100%',
});

const StyledTab = styled(Tab)(({ theme }) => ({
  fontSize: '1rem',
  fontWeight: 'bold',
  '&.Mui-selected': {
    color: '#1A237E',
  },
}));

function MobileRecharge({ walletShowHeader }) {
  const [loader, setLoader] = useState(false);
  const [modalShow, setModalShow] = useState(false);
  const [loading, setLoading] = useState(false);   // fetching plans (manual confirm)
  const [detecting, setDetecting] = useState(false); // auto-detecting operator
  const [bankData, setBankData] = useState([]);
  const [circleData, setCircleData] = useState([]);
  const [insufficientBalanceModal, setInsufficientBalanceModal] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isPaying, setIsPaying] = useState(false);
  const [showBank, setShowBank] = useState(null);
  const [selectCircle, setSelectCircle] = useState(null);
  const [allOperatorData, setAllOperatorData] = useState(null);
  const [tabValue, setTabValue] = useState(0);

  const [operatorDetected, setOperatorDetected] = useState(false);
  const [detectionFailed, setDetectionFailed] = useState(false);
  const [manualOverride, setManualOverride] = useState(false);

  const [initialData, setInitialData] = useState({
    billNumber: '',
    amount: ''
  });

  const bankChange = (event, newValue) => setShowBank(newValue);
  const circleChange = (event, newValue) => setSelectCircle(newValue);

  const rechargeOperator = async () => {
    setLoader(true);
    try {
      const res = await rechargeOperators();
      const circle = await getRechargeCircle();
      const mappedOperators = res?.data?.data?.map((item) => ({
        ...item,
        label: item.name,
      }));
      const mappedCircle = circle?.data?.data?.map((item) => ({
        label: item.stateName,
      }));
      setBankData(mappedOperators || []);
      setCircleData(mappedCircle || []);
    } catch (error) {
      console.error(error);
    } finally {
      setLoader(false);
    }
  };

  // Reset everything downstream whenever the mobile number changes
  const handleNumberChange = (e) => {
    const value = e.target.value;
    if (value.length > 11) return;

    setInitialData(prev => ({ ...prev, billNumber: value, amount: '' }));
    setAllOperatorData(null);
    setShowBank(null);
    setSelectCircle(null);
    setOperatorDetected(false);
    setDetectionFailed(false);
    setManualOverride(false);
  };

  // Single fetch function:
  // autoDetect=true  -> only mobileNumber + location sent, backend resolves operator/circle
  // autoDetect=false -> operator + circle sent explicitly (manual correction)
  const fetchPlans = useCallback(async ({ autoDetect, operatorId, circleLabel }) => {
    try {
      const { latitude, longitude } = await getLocation();
      if (!latitude || !longitude) {
        alert("Please Enable Location to Proceed Recharge.");
        return;
      }

      autoDetect ? setDetecting(true) : setLoading(true);

      const obj = {
        mobileNumber: initialData.billNumber,
        lat: latitude,
        long: longitude,
        ...(autoDetect ? {} : { opretorId: operatorId, state: circleLabel }),
      };

      const res = await mobilePlanDetails(obj);
      const data = res?.data?.data;
      setAllOperatorData(data);

      if (autoDetect) {
        const detectedOperator = bankData.find(
          (op) => op._id === data?.operator_code || op.operatorid === data?.operator_code
        );
        const detectedCircleLabel = data?.operator?.Circle;
        const detectedCircle = circleData.find((c) => c.label === detectedCircleLabel);

        if (detectedOperator) {
          setShowBank(detectedOperator);
          setSelectCircle(detectedCircle || (detectedCircleLabel ? { label: detectedCircleLabel } : null));
          setOperatorDetected(true);
          setDetectionFailed(false);
        } else {
          setOperatorDetected(false);
          setDetectionFailed(true);
          setManualOverride(true);
        }
      }
    } catch (error) {
      console.error(error);
      if (autoDetect) {
        setDetectionFailed(true);
        setManualOverride(true);
      }
    } finally {
      setDetecting(false);
      setLoading(false);
    }
  }, [initialData.billNumber, bankData, circleData]);

  // Auto-trigger detection once 10 digits are entered
  useEffect(() => {
    if (initialData.billNumber.length === 10 && bankData.length > 0) {
      fetchPlans({ autoDetect: true });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialData.billNumber, bankData.length]);

  const confirmManualSelection = () => {
    if (!showBank || !selectCircle) return;
    fetchPlans({ autoDetect: false, operatorId: showBank?.operatorid, circleLabel: selectCircle?.label });
    setOperatorDetected(true);
  };

  const selectAmount = (item) => {
    setInitialData(prev => ({ ...prev, amount: item?.rs }));
  };

  const toastMessage = (message, type) => {
    toast[type](message, {
      position: "top-center",
      autoClose: 2000,
    });
  };

  const submitData = async (tipin) => {
    setIsSubmitting(true);
    const data = {
      ...initialData,
      tpin: tipin,
      user_id: window.localStorage.getItem('userIdToken'),
      rechargeId: showBank?._id,
    };
    try {
      const res = await billPayRecharge(data);
      if (res.data.error === false) {
        toastMessage(res.data?.message, 'success');
        setShowBank(null);
        setInitialData({ billNumber: '', amount: '' });
        setOperatorDetected(false);
        setManualOverride(false);
        if (walletShowHeader) walletShowHeader();
      } else {
        toastMessage(res.data?.message, 'error');
        if (res.data?.message.toLowerCase().includes('insufficient balance')) {
          setErrorMessage(res.data?.message);
          setInsufficientBalanceModal(true);
        }
      }
    } catch (error) {
      setErrorMessage("An error occurred. Please try again.");
      setInsufficientBalanceModal(true);
    } finally {
      setIsSubmitting(false);
      setModalShow(false);
    }
  };

  const processToPay = () => {
    setModalShow(true);
  };

  useEffect(() => {
    rechargeOperator();
  }, []);

  const plansReady = allOperatorData && showBank && selectCircle;

  return (
    <>
      {(loading || loader) && <Loader />}
      <Container maxWidth="lg">
        <Typography
          variant="h3"
          component="h1"
          gutterBottom
          align="center"
          sx={{
            mt: 6,
            mb: 4,
            fontWeight: 'bold',
            color: '#1a237e',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
          }}
        >
          <PhoneAndroid sx={{ fontSize: '2rem', mr: 2 }} />
          <span>Mobile Recharge</span>
        </Typography>

        <StyledPaper elevation={3}>
          <Tabs
            value={tabValue}
            onChange={(e, newValue) => setTabValue(newValue)}
            centered
            sx={{ borderBottom: 1, borderColor: 'divider', mb: 3 }}
          >
            <StyledTab label="Rechage" />
            <StyledTab label="Recent Transactions" />
          </Tabs>

          <Box sx={{ p: 3 }}>
            {tabValue === 0 && (
              <Grid container spacing={3}>

                {/* STEP 1: Mobile number first */}
                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="Mobile Number"
                    variant="outlined"
                    name="billNumber"
                    value={initialData.billNumber}
                    onChange={handleNumberChange}
                    margin="normal"
                    type="number"
                    InputProps={{
                      startAdornment: <PhoneAndroid sx={{ mr: 1 }} />,
                      endAdornment: detecting ? <CircularProgress size={18} /> : null,
                    }}
                  />
                </Grid>

                {/* STEP 2: Auto-detected operator shown as a chip */}
                {operatorDetected && !manualOverride && (
                  <Grid item xs={12} md={6} sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: 2 }}>
                    <Chip
                      icon={<CheckCircle />}
                      color="success"
                      variant="outlined"
                      label={`${showBank?.label || 'Operator'} • ${selectCircle?.label || 'Circle'}`}
                    />
                    <Link
                      component="button"
                      variant="body2"
                      onClick={() => setManualOverride(true)}
                      sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}
                    >
                      <Edit fontSize="inherit" /> Not correct? Change operator
                    </Link>
                  </Grid>
                )}

                {detectionFailed && !manualOverride && (
                  <Grid item xs={12}>
                    <Typography color="error" variant="body2">
                      Couldn't auto-detect your operator. Please select it below.
                    </Typography>
                  </Grid>
                )}

                {/* STEP 3: Manual selection, only shown if detection failed or user wants to change it */}
                {manualOverride && (
                  <>
                    <Grid item xs={12} md={6}>
                      <Autocomplete
                        fullWidth
                        options={bankData}
                        getOptionLabel={(option) => option.label || ''}
                        value={showBank}
                        onChange={bankChange}
                        renderInput={(params) => (
                          <TextField
                            {...params}
                            label="Select Operator"
                            variant="outlined"
                            margin="normal"
                            InputProps={{
                              ...params.InputProps,
                              startAdornment: (
                                <>
                                  <SimCard />
                                  {params.InputProps.startAdornment}
                                </>
                              ),
                            }}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} md={6}>
                      <Autocomplete
                        fullWidth
                        options={circleData}
                        getOptionLabel={(option) => option.label || ''}
                        value={selectCircle}
                        onChange={circleChange}
                        renderInput={(params) => (
                          <TextField
                            {...params}
                            label="Select Circle"
                            variant="outlined"
                            margin="normal"
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sx={{ display: 'flex', justifyContent: 'center' }}>
                      <Grid item xs={12} sm={4}>
                        <AnimatedButton whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.98 }}>
                          <Button
                            variant="contained"
                            color="primary"
                            fullWidth
                            disabled={!showBank || !selectCircle || loading}
                            onClick={confirmManualSelection}
                            sx={{ mt: 1, py: 1.5, borderRadius: '12px' }}
                            startIcon={loading ? <CircularProgress size={20} color="inherit" /> : <Payment />}
                          >
                            {loading ? <CircularProgress size={24} /> : 'Confirm Operator & Show Plans'}
                          </Button>
                        </AnimatedButton>
                      </Grid>
                    </Grid>
                  </>
                )}

                {/* STEP 4: Plans */}
                {plansReady && (
                  <Grid item xs={12}>
                    <MobilePlan allOperatorDat={allOperatorData} selectAmount={selectAmount} />
                  </Grid>
                )}

                {/* STEP 5: Amount + Pay */}
                {plansReady && (
                  <>
                    <Grid item xs={12} md={6}>
                      <TextField
                        fullWidth
                        label="Amount"
                        variant="outlined"
                        name="amount"
                        disabled
                        value={initialData.amount}
                        margin="normal"
                        type="number"
                        InputProps={{
                          startAdornment: <Payment />,
                        }}
                      />
                    </Grid>

                    <Grid item xs={12} sx={{ display: 'flex', justifyContent: 'center' }}>
                      <Grid item xs={12} sm={4}>
                        <AnimatedButton whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.98 }}>
                          <Button
                            variant="contained"
                            color="primary"
                            fullWidth
                            disabled={!initialData.amount || !initialData.billNumber || !showBank || isPaying}
                            onClick={processToPay}
                            sx={{ mt: 2, py: 1.5, borderRadius: '12px' }}
                            startIcon={isPaying ? <CircularProgress size={20} color="inherit" /> : <Payment />}
                          >
                            {isPaying ? <CircularProgress size={24} /> : `Process to Pay ${initialData.amount}`}
                          </Button>
                        </AnimatedButton>
                      </Grid>
                    </Grid>
                  </>
                )}
              </Grid>
            )}

            {tabValue === 1 && (
              <MobileRechargeList />
            )}
          </Box>
        </StyledPaper>
      </Container>

      <TipinModal
        show={modalShow}
        onHide={() => setModalShow(false)}
        submitata={submitData}
        isSubmitting={isSubmitting}
        initialData={initialData}
      />

      <InsufficientBalanceModal
        show={insufficientBalanceModal}
        onHide={() => setInsufficientBalanceModal(false)}
        errorMessage={errorMessage}
      />
    </>
  );
}

export default MobileRecharge;